const cfg = $('Gemini Prompt').first().json;
const rawResponse = $json;

let parsed = {};
let parseSuccess = false;

try {
  let raw = '';
  if (rawResponse.choices && rawResponse.choices[0]) {
    raw = rawResponse.choices[0].message.content || '';
  } else if (rawResponse.candidates && rawResponse.candidates[0]) {
    raw = rawResponse.candidates[0].content.parts.map(p => p.text).join('');
  } else {
    console.log('UNKNOWN RESPONSE:', JSON.stringify(rawResponse).substring(0, 300));
    raw = JSON.stringify(rawResponse);
  }

  console.log('AI raw length: ' + raw.length);
  console.log('AI start: ' + raw.substring(0, 200));

  let cleaned = raw.replace(/```json\n?/gi, '').replace(/```\n?/g, '').trim();

  try { parsed = JSON.parse(cleaned); parseSuccess = true; } catch(e1) {
    try {
      const m = cleaned.match(/\{[\s\S]*\}/);
      if (m) { parsed = JSON.parse(m[0]); parseSuccess = true; }
    } catch(e2) {
      try {
        let fixed = cleaned.replace(/,\s*}/g, '}').replace(/,\s*]/g, ']');
        const m2 = fixed.match(/\{[\s\S]*\}/);
        if (m2) { parsed = JSON.parse(m2[0]); parseSuccess = true; }
      } catch(e3) { console.log('JSON PARSE FAILED: ' + e3.message); }
    }
  }
} catch(outerErr) { console.log('Error: ' + outerErr.message); }

console.log('Parse OK: ' + parseSuccess + ', Title: ' + (parsed.title || 'N/A'));

if (!parseSuccess || !parsed.articleHTML || parsed.articleHTML.length < 100) {
  console.log('STOPPING: No valid article');
  return [];
}

let html = parsed.articleHTML;
const seenUrls = new Set();
html = html.replace(/<img[^>]+src=["']([^"']+)["'][^>]*>/gi, (match, src) => {
  const key = src.split('?')[0].split('#')[0];
  if (seenUrls.has(key)) return '';
  seenUrls.add(key);
  return match;
});
html = html.replace(/<img[^>]+wp-content\/uploads[^>]+>/gi, '');

const inlineImages = cfg.inlineImages || (cfg.scrapedImages || []).slice(1);
if (inlineImages.length > 0) {
  let h2s = []; let ss = 0;
  while (true) { const i = html.indexOf('<h2', ss); if (i === -1) break; const e = html.indexOf('</h2>', i); if (e === -1) break; h2s.push(e + 5); ss = e + 5; }
  let offset = 0;
  for (let i = 0; i < inlineImages.length && i < h2s.length; i++) {
    if (!html.includes(inlineImages[i])) {
      const tag = '<img src="' + inlineImages[i] + '" alt="' + (cfg.topic || 'Bild').replace(/"/g, '') + '" class="wp-image size-large" loading="lazy" />';
      const np = html.indexOf('</p>', h2s[i] + offset);
      if (np > -1) { html = html.substring(0, np+4) + '\n' + tag + html.substring(np+4); offset += tag.length + 1; }
    }
  }
}

const postBody = {
  title: parsed.title || cfg.topic,
  content: html,
  status: 'publish',
  categories: [parsed.category_id || 1],
  excerpt: parsed.metaDescription || ''
};
if (cfg.featured_media && cfg.featured_media > 0) postBody.featured_media = cfg.featured_media;

console.log('PUBLISHING: ' + postBody.title);
return [{json: {_postBody: postBody, _featuredMediaId: cfg.featured_media || 0}}];

const scrape = $('Build Image List').first().json;
const uploadResponse = $('Upload to WP Media').first().json;

let featured_media = null;
let wpImageUrl = '';

if (uploadResponse && uploadResponse.id && !isNaN(parseInt(uploadResponse.id))) {
  featured_media = parseInt(uploadResponse.id);
  wpImageUrl = uploadResponse.source_url || '';
  console.log('✅ Featured image uploaded OK — WP Media ID:', featured_media, '| URL:', wpImageUrl);
} else {
  console.log('⚠️ Featured image upload failed. Response:', JSON.stringify(uploadResponse).substring(0, 200));
}

const allImages = scrape.scrapedImages || [];
const finalImages = allImages.map((url, idx) => idx === 0 && wpImageUrl ? wpImageUrl : url);
const topicAlt = (scrape.topic || 'Flohmarkt').replace(/"/g, '').substring(0, 60);

const imageSnippets = finalImages.map((url, idx) => {
  const alt = topicAlt + (idx === 0 ? ' - Hauptbild' : ' - Bild ' + (idx + 1));
  return '<img src="' + url + '" alt="' + alt + '" class="wp-image size-large" loading="lazy" />';
});

console.log('Total images for article: ' + imageSnippets.length);

let imgBlock = '';
if (imageSnippets.length > 0) {
  imgBlock = '\n\nBILDER (' + imageSnippets.length + ' Stueck):\n';
  imageSnippets.forEach((html, idx) => {
    const pos = idx === 0 ? 'nach Einleitung' : 'nach H2 ' + idx;
    imgBlock += 'BILD ' + (idx + 1) + ' (' + pos + '):\n' + html + '\n\n';
  });
  imgBlock += 'Jedes Bild GENAU EINMAL! KEIN Bild doppelt!';
}

const angles = ['Geheimtipps', 'Fehler vermeiden', 'Insider-Wissen', 'Praktischer Ratgeber', 'Schritt-fuer-Schritt', 'Pro und Contra', 'Mythen entlarven', 'Zukunftstrends', 'Anfaenger-Guide'];
const angle = angles[Math.floor(Math.random() * angles.length)];

const sys = 'Du bist ein professioneller deutscher SEO-Redakteur.\n\n' +
  'SPRACHE: ZWINGEND AUF DEUTSCH, auch wenn die Quelle Englisch ist.\n' +
  'EINZIGARTIGKEIT: Schreibe VOLLSTAENDIG NEU!\n' +
  'Dein BLICKWINKEL: ' + angle + '\n' +
  'KEINE generischen Titel. Nutze kreative Formate.\n\n' +
  'STRUKTUR (KEIN H1):\n' +
  '<article><p>[Einleitung]</p>[BILD 1]<h2>[H2]</h2><p>[Text]</p>[BILD 2]<h2>[H2]</h2><p>[Text]</p>[BILD 3]<h2>FAQ</h2><h3>[3 Fragen]</h3><h2>Fazit</h2><p>[CTA]</p></article>' + imgBlock + '\n\n' +
  'Antworte NUR mit JSON:\n{"title":"Titel","slug":"slug","metaDescription":"Meta 150 Zeichen","category_id":1,"articleHTML":"<article>...</article>","keywords":["k1","k2","k3"]}';

const usr = 'Thema: ' + scrape.topic + '\nBlickwinkel: ' + angle + '\n' + (scrape.rssDescription || '') + '\n' + (scrape.parsedText || '').substring(0, 3000);

const body = {
  model: 'google/gemini-2.0-flash-001',
  messages: [
    { role: 'system', content: sys },
    { role: 'user', content: usr }
  ],
  max_tokens: 8000,
  temperature: 0.75,
  response_format: { type: 'json_object' }
};

return [{json: {...scrape, featured_media, scrapedImages: finalImages, inlineImages: finalImages.slice(1), _aiBody: body}}];

const inputData = $json;
const html = inputData.data || inputData.body || '';
if (!html || html.length < 100) {
  console.log('Empty HTML');
  return [{json: {...inputData, parsedText: '', scrapedImages: []}}];
}

const images = [];
const seenBasenames = new Set();

function addImage(url) {
  if (!url || url.length < 20) return;
  if (!url.startsWith('http')) {
    if (url.startsWith('//')) url = 'https:' + url;
    else if (url.startsWith('/')) {
      try { url = new URL(inputData.redirectUrl).origin + url; } catch(e) { return; }
    } else return;
  }
  const lower = url.toLowerCase();
  if (lower.includes('logo') || lower.includes('icon') || lower.includes('avatar') ||
      lower.includes('pixel') || lower.includes('1x1') || lower.includes('spacer') ||
      lower.includes('tracking') || lower.includes('badge') || lower.includes('button') ||
      lower.includes('transparent') || lower.includes('data:image') ||
      lower.includes('google.com/') || lower.includes('gstatic.com') ||
      lower.includes('facebook.com') || lower.includes('twitter.com') ||
      lower.includes('.svg') || lower.includes('.gif') || lower.length < 30) return;
  const basename = url.split('/').pop().split('?')[0].split('#')[0].toLowerCase();
  if (basename.length < 4 || seenBasenames.has(basename)) return;
  seenBasenames.add(basename);
  images.push(url);
}

const ogImage = html.match(/<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i) ||
                html.match(/<meta[^>]+content=["']([^"']+)["'][^>]+property=["']og:image["']/i);
if (ogImage) addImage(ogImage[1]);

const twitImg = html.match(/<meta[^>]+name=["']twitter:image["'][^>]+content=["']([^"']+)["']/i) ||
               html.match(/<meta[^>]+content=["']([^"']+)["'][^>]+name=["']twitter:image["']/i);
if (twitImg) addImage(twitImg[1]);

const articleMatch = html.match(/<article[^>]*>([\s\S]*?)<\/article>/i) ||
                     html.match(/<div[^>]+class=["'][^"']*(?:article|post|content|entry|story)[^"']*["'][^>]*>([\s\S]*?)<\/div>/i);
const articleHtml = articleMatch ? articleMatch[1] : html;

const imgTags = articleHtml.match(/<img[^>]+>/gi) || [];
for (const tag of imgTags) {
  const srcMatch = tag.match(/(?:data-src|data-lazy-src|src)=["']([^"']+)["']/i);
  if (srcMatch) addImage(srcMatch[1]);
}

const figures = articleHtml.match(/<figure[^>]*>[\s\S]*?<\/figure>/gi) || [];
for (const fig of figures) {
  const srcset = fig.match(/srcset=["']([^"']+)["']/i);
  if (srcset) {
    const parts = srcset[1].split(',').map(s => s.trim());
    const largest = parts[parts.length - 1].split(' ')[0];
    addImage(largest);
  }
}

const finalImages = images.slice(0, 5);
console.log('Scraped ' + finalImages.length + ' unique images');
finalImages.forEach((img, i) => console.log('  Img ' + (i+1) + ': ' + img.substring(0, 80)));

let text = '';
const textBlocks = articleHtml.match(/<p[^>]*>([\s\S]*?)<\/p>/gi) || [];
for (const block of textBlocks) {
  text += block.replace(/<[^>]+>/g, '').trim() + ' ';
}
if (text.length < 200) text = html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();

return [{json: {...inputData, parsedText: text.substring(0, 5000), scrapedImages: finalImages}}];

const html = ($json.data || $json.body || '').toLowerCase();
const blocked = html.includes('consent') || html.includes('einwilligung') || html.includes('pur-abo') || html.includes('block') || html.length < 1000;
return [{json:{...$input.first().json, isBlocked: blocked, rawHtml: $json.data || $json.body || '' }}];

const USED_KEY = 'usedLinks';
const USED_TITLES_KEY = 'usedTitles';
const all = $input.all();
const kw = ['flohmarkt','troedelmarkt','antik','vintage','sammler','secondhand','upcycling','retro','markt','nachhaltigkeit','recycling','diy','einrichten','wohnen','deko','garten','design','interior','handwerk','kreativ','basteln','lifestyle','trend','ideen','tipps','ratgeber','sparen','gebraucht','nachhaltig','moebel','renovieren','restaurieren'];
let items = [];
for (const it of all) {
  const raw = it.json.data || it.json.body || '';
  if (!raw || raw.length < 50) continue;
  const xs = raw.match(/<item>[\s\S]*?<\/item>/g) || [];
  for (const x of xs) {
    const t1 = x.match(/<title><!\[CDATA\[([^\]]+)\]\]><\/title>/);
    const t2 = x.match(/<title>([^<]+)<\/title>/);
    const title = (t1?.[1] || t2?.[1] || '').trim();
    const l1 = x.match(/<link>([^<]+)<\/link>/);
    let link = l1?.[1] || '';
    if (link.includes('url=')) try { link = decodeURIComponent(link.split('url=')[1].split('&')[0]); } catch(e) {}
    const d1 = x.match(/<description><!\[CDATA\[([\s\S]*?)\]\]><\/description>/);
    const d2 = x.match(/<description>([^<]+)<\/description>/);
    const desc = (d1?.[1] || d2?.[1] || '').trim();
    if (title && link) {
      const combined = (title + ' ' + desc).toLowerCase();
      const hasKw = kw.some(k => combined.includes(k));
      items.push({title, link, desc: desc.replace(/<[^>]+>/g, '').trim(), priority: hasKw ? 1 : 2});
    }
  }
}
items.sort((a, b) => a.priority - b.priority);
console.log('Total articles found: ' + items.length);
if (items.length === 0) { console.log('NO ARTICLES FOUND'); return []; }

const today = new Date().toISOString().slice(0, 10);
const gd = $getWorkflowStaticData('global');
let used = {}; try { used = JSON.parse(gd[USED_KEY] || '{}'); } catch(e) {}
let usedT = []; try { usedT = JSON.parse(gd[USED_TITLES_KEY] || '[]'); } catch(e) {}
const cutoff = new Date(); cutoff.setDate(cutoff.getDate() - 30);
Object.keys(used).forEach(d => { if (d < cutoff.toISOString().slice(0, 10)) delete used[d]; });
if (usedT.length > 100) usedT = usedT.slice(-50);
const allUsed = Object.values(used).flat();

function wordOverlap(a, b) {
  const wa = a.split(/\s+/).filter(w => w.length > 3);
  const wb = new Set(b.split(/\s+/).filter(w => w.length > 3));
  if (wa.length === 0) return 0;
  return wa.filter(w => wb.has(w)).length / wa.length;
}
let fresh = items.filter(i => !allUsed.includes(i.link) && !usedT.some(t => t === i.title.toLowerCase() || wordOverlap(i.title.toLowerCase(), t) > 0.6));
console.log('Fresh articles: ' + fresh.length);
if (fresh.length === 0) fresh = items.filter(i => !allUsed.includes(i.link));
if (fresh.length === 0) fresh = items;

const sel = fresh[Math.floor(Math.random() * Math.min(fresh.length, 5))];
if (!used[today]) used[today] = [];
used[today].push(sel.link);
usedT.push(sel.title.toLowerCase());
gd[USED_KEY] = JSON.stringify(used);
gd[USED_TITLES_KEY] = JSON.stringify(usedT);
console.log('Selected: ' + sel.title);
return [{json: {topic: sel.title, redirectUrl: sel.link, rssDescription: sel.desc}}];

const inputData = $json;
const scraped = inputData.scrapedImages || [];
const validImages = [];
const seenBasenames = new Set();

for (const img of scraped) {
  if (img.startsWith('http') && img.length > 20 && !img.includes('placeholder') && !img.includes('data:image') && !img.includes('icon') && !img.includes('logo') && !img.includes('1x1') && !img.includes('pixel') && !img.includes('spacer') && !img.includes('tracking') && !img.includes('google.com/') && !img.includes('gstatic.com') && !img.includes('badge') && !img.includes('button') && !img.includes('avatar')) {
    const basename = img.split('/').pop().split('?')[0].split('#')[0].toLowerCase();
    if (!seenBasenames.has(basename) && basename.length > 3) {
      seenBasenames.add(basename);
      validImages.push(img);
    }
  }
}

const finalImages = validImages.slice(0, 5);
console.log('Unique valid images: ' + finalImages.length + ' from ' + scraped.length + ' scraped');
finalImages.forEach((img, i) => console.log('Img ' + (i+1) + ': ' + img.substring(0, 80)));

if (finalImages.length === 0) {
  console.log('NO VALID IMAGES - STOPPING. No blog will be published.');
  return [];
}

return [{json: { ...inputData, scrapedImages: finalImages, hasRealImages: true }}];
